const SIZE = 4;

let grid = [];
for (let i = 0; i < SIZE; i++) {
    const line = readline();
    console.error(line);
    grid = grid.concat([...line]);
}

let symbols = new Set(grid);
symbols.delete(".");
symbols = [...symbols];
console.error("Symbols:", ...symbols);
if(symbols.length !== SIZE) {
    console.log("Invalid");
} else {
    let freeSpots = [...grid.keys()].filter(i => grid[i] === ".");
    console.error("Free Spots:", ...freeSpots);
    let possibleEntries = freeSpots.map(i => symbols.filter(c => isValid(set(grid, i, c))));
    console.error("Possible Entries:", ...possibleEntries);

    let missing = [];

    if(dfs(grid, freeSpots, possibleEntries, missing)) {
        console.log(...missing);
    } else {
        console.log("Invalid");
    }
}

function dfs(grid, freeSpots, possibleEntries, missing) {
    if(!isValid(grid)) return false;
    if(freeSpots.length === 0) return true;

    let spot = freeSpots[0];
    for(let c of possibleEntries[0]) {
        let newGrid = set(grid, spot, c);
        missing.push(c);
        if(dfs(newGrid, freeSpots.slice(1), possibleEntries.slice(1), missing)) {
            return true;
        }
        missing.pop();
    }
    return false;
}

function set(array, index, value) {
    let newArray = array.slice();
    newArray[index] = value;
    return newArray;
}

function isValid(grid) {
    for(let i = 0; i < SIZE; i++) {
        for(let f of [getRow, getColumn]) {
            let arr = f(grid, i);
            let repeats = [];
            for(let c of arr) {
                if(c !== "." && !repeats[c]) {
                    repeats[c] = 1;
                } else {
                    repeats[c]++;
                }
            }
            for(let i in repeats) {
                if(repeats[i] > 1) return false;
            }
        }
    }
    return true;
}

function getRow(grid, i) {
    return grid.slice(SIZE*i, SIZE*(i+1));
}

function getColumn(grid, i) {
    return grid.filter((_, j) => j % SIZE === i);
}
